import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getStablecoinDominance(chainName) {
  const stablecoins = ["USDC", "USDT", "DAI", "FRAX", "LUSD"];
  const results = await Promise.all(
    stablecoins.map(symbol =>
      client.PricingService.getTokenPrices(chainName, "USD", symbol)
    )
  );
  return results.map((r, i) => ({
    symbol: stablecoins[i],
    price: r.data?.items?.[0]?.price ?? null,
    pegDeviation: Math.abs((r.data?.items?.[0]?.price ?? 1) - 1),
  }));
}
